Exposing character death events to blueprints:

```cpp
#include

// Declare dynamic multi-cast signature (accessible from BP)
DECLARE_DYNAMIC_MULTICAST_DELEGATE_OneParam(FOnDeathSignature, AActor*, Killer);

UCLASS()
class ACombatActor : public AActor {
    GENERATED_BODY()

public:
    UPROPERTY(BlueprintAssignable, Category =

)
    FOnDeathSignature OnDeathEvent;

    void ApplyFatalDamage(AActor* DamageCauser) {
        // Broadcast calls all bound listener functions on server and clients
        OnDeathEvent.Broadcast(DamageCauser);
    }
};
```
